#include<bits/stdc++.h>
using namespace std;
int a[7010],dp[7010][7010],sum[7010];
const int mod=1e9+7;
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&a[i]);
    }
    if(m==1&&a[1]<n)
    {
        printf("0");
        return 0;
    }
    for(int i=1;i<=m;i++)
    {
        dp[1][i]=1;
    }
    sum[1]=m;
    for(int i=2;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            dp[i][j]=sum[i-1];
            if(i>a[j])
            {
                if(i==a[j]+1)
                {
                    dp[i][j]=(dp[i][j]-1+mod)%mod;
                }
                else
                {
                    dp[i][j]=((dp[i][j]-(sum[i-a[j]-1]-dp[i-a[j]-1][j])%mod)%mod+mod)%mod;
                }
            }
            sum[i]=(sum[i]+dp[i][j])%mod;
        }
    }
    printf("%d",sum[n]);
    return 0;
}
